content:
s.zone_boundaries[z + 1]) / 2.0
        }).collect();

        let result = apply_depth_luts(&pixels, &depth, &depth_luts);

        for (i, (orig, out)) in pixels.iter().zip(result.iter()).enumerate() {
            for c in 0..3 {
                assert!(
                    (orig[c] - out[c]).abs() < 1e-4,
                    "pixel {i} channel {c}: expected {:.4} got {:.4}",
                    orig[c],
                    out[c]
                );
            }
        }
    }

